def boundary_search(
    baseline_prompt: str,
    failing_prompt: str,
    model: str,
    test_dimensions: list[str],
) -> dict:
    # Systematically vary the failing prompt along test dimensions.
    results = {}
    for dim in test_dimensions:
        variants = generate_variants(failing_prompt, dimension=dim)
        for variant in variants:
            resp = call_model(model, variant)
            results[dim] = results.get(dim, [])
            results[dim].append({
                "variant": variant[:100],
                "failed": is_failure(resp),
            })
    # Identify minimum failing condition
    triggers = {
        dim: [v for v in variants if v["failed"]]
        for dim, variants in results.items()
    }
    return {"triggers": triggers, "summary": summarise_triggers(triggers)}

# test_dimensions examples for refusal-rate incidents:
